const historyTimeline = document.querySelector("[data-history-timeline]");

function escapeTimelineText(value = "") {
  return String(value).replace(/[&<>"']/g, (character) => ({
    "&": "&amp;",
    "<": "&lt;",
    ">": "&gt;",
    "\"": "&quot;",
    "'": "&#039;"
  }[character]));
}

function renderHistoryTimeline() {
  if (!historyTimeline) return;
  const groups = missionMilestones[currentLanguage()] || missionMilestones.en;

  historyTimeline.innerHTML = groups.map((group) => `
    <li class="history-era">
      <article class="history-era__card">
        <header class="history-era__header">
          <span class="history-era__period">${escapeTimelineText(group.period)}</span>
          <h4 class="history-era__title">${escapeTimelineText(group.title)}</h4>
        </header>
        <ul class="history-era__entries">
          ${group.items.map(([year, title, location]) => `
            <li class="history-era__entry">
              <time class="history-era__year">${escapeTimelineText(year)}</time>
              <div class="history-era__entry-copy">
                <span class="history-era__entry-title">${escapeTimelineText(title)}</span>
                <span class="history-era__entry-location">${escapeTimelineText(location)}</span>
              </div>
            </li>
          `).join("")}
        </ul>
      </article>
    </li>
  `).join("");
}

