const prefersReducedMotion = window.matchMedia("(prefers-reduced-motion: reduce)");

function currentLanguage() {
  return activeLanguage;
}


/* -------- Read more / show less for long written content -------- */
let readMoreId = 0;

function getReadMoreToggle(content) {
  const next = content.nextElementSibling;
  return next?.matches?.("[data-read-more-toggle]") ? next : null;
}

function ensureReadMoreToggle(content) {
  let button = getReadMoreToggle(content);

  if (!content.id) {
    readMoreId += 1;
    content.id = `read-more-content-${readMoreId}`;
  }

  if (!button) {
    button = document.createElement("button");
    button.type = "button";
    button.className = "read-more-toggle";
    button.dataset.readMoreToggle = "";
    content.insertAdjacentElement("afterend", button);
  }

  button.setAttribute("aria-controls", content.id);

  if (button.dataset.readMoreBound !== "true") {
    button.addEventListener("click", () => {
      const expanded = content.dataset.readMoreExpanded !== "true";
      content.dataset.readMoreExpanded = String(expanded);
      refreshReadMoreContent();
    });
    button.dataset.readMoreBound = "true";
  }

  return button;
}

function refreshReadMoreContent({ reset = false } = {}) {
  const dictionary = copy[currentLanguage()];

  document.querySelectorAll("[data-read-more]").forEach((content) => {
    const button = ensureReadMoreToggle(content);
    const minimumLength = Number(content.dataset.readMoreMin || 260);
    const normalizedText = content.textContent.replace(/\s+/g, " ").trim();
    const needsToggle = normalizedText.length > minimumLength;

    if (!needsToggle) {
      content.classList.remove("is-collapsed");
      content.dataset.readMoreExpanded = "true";
      button.hidden = true;
      return;
    }

    const expanded = !reset && content.dataset.readMoreExpanded === "true";
    content.dataset.readMoreExpanded = String(expanded);
    content.classList.toggle("is-collapsed", !expanded);

    button.hidden = false;
    button.setAttribute("aria-expanded", String(expanded));
    button.textContent = expanded ? dictionary.showLess : dictionary.readMore;
  });
}

function initializeReadMoreContent() {
  refreshReadMoreContent({ reset: true });
}

function imageFallback(image) {
  const fallback = image.dataset.fallback || "img/placeholder-photo.svg";
  if (image.dataset.hasFallback === "true") return;
  image.dataset.hasFallback = "true";
  image.src = fallback;
}

function attachImageFallbacks() {
  document.querySelectorAll("img[data-fallback]").forEach((image) => {
    image.addEventListener("error", () => imageFallback(image));
  });
}

function applyTranslations(language) {
  const dictionary = copy[language];
  if (!dictionary) return;

  document.documentElement.lang = language;
  document.title = dictionary.pageTitle;

  document.querySelectorAll("[data-i18n]").forEach((element) => {
    const key = element.dataset.i18n;
    if (dictionary[key] !== undefined) element.textContent = dictionary[key];
  });

  document.querySelectorAll("[data-i18n-html]").forEach((element) => {
    const key = element.dataset.i18nHtml;
    if (dictionary[key] !== undefined) element.innerHTML = dictionary[key];
  });

  document.querySelectorAll("[data-i18n-alt]").forEach((element) => {
    const key = element.dataset.i18nAlt;
    if (dictionary[key] !== undefined) element.alt = dictionary[key];
  });

  document.querySelectorAll("[data-i18n-title]").forEach((element) => {
    const key = element.dataset.i18nTitle;
    if (dictionary[key] !== undefined) element.title = dictionary[key];
  });

  document.querySelectorAll("[data-i18n-aria-label]").forEach((element) => {
    const key = element.dataset.i18nAriaLabel;
    if (dictionary[key] !== undefined) element.setAttribute("aria-label", dictionary[key]);
  });

  if (languageToggle) {
    languageToggle.setAttribute("aria-label", dictionary.languageToggle);
    languageToggle.setAttribute("title", dictionary.languageToggle);
  }
  if (languageTargetLabel) languageTargetLabel.textContent = dictionary.languageTarget;
  if (menuToggle) menuToggle.setAttribute("aria-label", menuToggle.classList.contains("is-open") ? dictionary.menuClose : dictionary.menuOpen);

  renderHistoryTimeline();
  updateGalleryLanguage();
  updateTrainingGalleryLanguage();
  updatePlaceContent(false);
  populateBibleBooks();
  refreshZoomableLabels();
  refreshReadMoreContent({ reset: true });
}

function setLanguage(language) {
  if (!copy[language]) return;
  activeLanguage = language;
  applyTranslations(language);
  localStorage.setItem("sgm-language", language);
}

languageToggle?.addEventListener("click", () => setLanguage(currentLanguage() === "en" ? "es" : "en"));

function closeMenu() {
  if (!menuToggle || !primaryNav) return;
  menuToggle.classList.remove("is-open");
  menuToggle.setAttribute("aria-expanded", "false");
  primaryNav.classList.remove("is-open");
  document.body.classList.remove("menu-open");
  menuToggle.setAttribute("aria-label", copy[currentLanguage()].menuOpen);
}

menuToggle?.addEventListener("click", () => {
  const isOpen = menuToggle.classList.toggle("is-open");
  menuToggle.setAttribute("aria-expanded", String(isOpen));
  primaryNav?.classList.toggle("is-open", isOpen);
  document.body.classList.toggle("menu-open", isOpen);
  menuToggle.setAttribute("aria-label", isOpen ? copy[currentLanguage()].menuClose : copy[currentLanguage()].menuOpen);
});

primaryNav?.querySelectorAll("a").forEach((link) => link.addEventListener("click", closeMenu));

window.addEventListener("scroll", () => header?.classList.toggle("is-scrolled", window.scrollY > 8), { passive: true });

const revealObserver = new IntersectionObserver((entries) => {
  entries.forEach((entry) => {
    if (!entry.isIntersecting) return;
    entry.target.classList.add("is-visible");
    revealObserver.unobserve(entry.target);
  });
}, { threshold: .12 });
document.querySelectorAll(".reveal").forEach((element) => revealObserver.observe(element));

const navObserver = new IntersectionObserver((entries) => {
  entries.forEach((entry) => {
    if (!entry.isIntersecting) return;
    const target = entry.target.dataset.navTarget;
    if (!target) return;
    navLinks.forEach((link) => link.classList.toggle("is-current", link.getAttribute("href") === target));
  });
}, { rootMargin: "-30% 0px -58% 0px", threshold: .01 });
navSections.forEach((section) => navObserver.observe(section));

/* -------- One universal photo viewer for every content image -------- */
const lightbox = document.querySelector("[data-gallery-lightbox]");
const lightboxImage = lightbox?.querySelector("[data-lightbox-image]");
const lightboxCaption = lightbox?.querySelector("[data-lightbox-caption]");
const lightboxCloseButton = lightbox?.querySelector("[data-lightbox-close]");
const lightboxPreviousButton = lightbox?.querySelector("[data-lightbox-prev]");
const lightboxNextButton = lightbox?.querySelector("[data-lightbox-next]");
let lightboxItems = [];
let lightboxIndex = 0;
let lastFocusedElement = null;

function setImageSource(image, src, alt = "") {
  if (!image) return;
  image.dataset.hasFallback = "";
  image.onerror = () => {
    image.onerror = null;
    image.src = "img/placeholder-photo.svg";
  };
  image.src = src;
  image.alt = alt;
}

function normalizeLightboxItem(item) {
  return typeof item === "string" ? { src: item, caption: "" } : item;
}

function updateLightboxView() {
  if (!lightbox || !lightboxItems.length) return;
  const item = normalizeLightboxItem(lightboxItems[lightboxIndex]);
  setImageSource(lightboxImage, item.src, item.caption || "Expanded photo");
  if (lightboxCaption) lightboxCaption.textContent = item.caption || "";
  const hasMultiple = lightboxItems.length > 1;
  lightboxPreviousButton?.toggleAttribute("hidden", !hasMultiple);
  lightboxNextButton?.toggleAttribute("hidden", !hasMultiple);
}

function openLightbox(items, index = 0, trigger = document.activeElement) {
  if (!lightbox || !items?.length) return;
  lastFocusedElement = trigger;
  lightboxItems = items.map(normalizeLightboxItem);
  lightboxIndex = (index + lightboxItems.length) % lightboxItems.length;
  stopGalleryTimer();
  stopPlaceTimer();
  stopTrainingTimer();
  updateLightboxView();
  lightbox.classList.add("is-open");
  lightbox.setAttribute("aria-hidden", "false");
  document.body.classList.add("gallery-is-open");
  lightboxCloseButton?.focus();
}

function closeLightbox() {
  if (!lightbox) return;
  lightbox.classList.remove("is-open");
  lightbox.setAttribute("aria-hidden", "true");
  document.body.classList.remove("gallery-is-open");
  lastFocusedElement?.focus?.();
  startGalleryTimer();
  startPlaceTimer();
  startTrainingTimer();
}

function moveLightbox(step) {
  if (!lightboxItems.length) return;
  lightboxIndex = (lightboxIndex + step + lightboxItems.length) % lightboxItems.length;
  updateLightboxView();
}

lightboxCloseButton?.addEventListener("click", closeLightbox);
lightboxPreviousButton?.addEventListener("click", () => moveLightbox(-1));
lightboxNextButton?.addEventListener("click", () => moveLightbox(1));
lightbox?.addEventListener("click", (event) => { if (event.target === lightbox) closeLightbox(); });

/* -------- Main mission gallery -------- */
const gallery = document.querySelector("[data-mission-gallery]");
const galleryImage = gallery?.querySelector("[data-gallery-image]");
const galleryOpenButtons = gallery?.querySelectorAll("[data-gallery-open]");
const galleryPreviousButton = gallery?.querySelector("[data-gallery-prev]");
const galleryNextButton = gallery?.querySelector("[data-gallery-next]");
const galleryDots = gallery?.querySelector("[data-gallery-dots]");
const galleryCount = gallery?.querySelector("[data-gallery-count]");
const galleryStatus = gallery?.querySelector("[data-gallery-status]");
let currentGalleryIndex = 0;
let galleryTimer = null;
let galleryTouchStartX = 0;

function getGalleryItems() {
  return gallerySlides.map((slide) => ({ src: slide.src, caption: slide[currentLanguage()] }));
}
function galleryCaption() { return gallerySlides[currentGalleryIndex][currentLanguage()]; }
function createGalleryDots() {
  if (!galleryDots) return;
  galleryDots.innerHTML = "";
  gallerySlides.forEach((_, index) => {
    const dot = document.createElement("button");
    dot.type = "button";
    dot.className = "mission-gallery__dot";
    dot.addEventListener("click", () => { showGallerySlide(index); restartGalleryTimer(); });
    galleryDots.appendChild(dot);
  });
}
function updateGalleryDots() {
  galleryDots?.querySelectorAll(".mission-gallery__dot").forEach((dot, index) => {
    dot.classList.toggle("is-active", index === currentGalleryIndex);
    dot.setAttribute("aria-current", String(index === currentGalleryIndex));
  });
}
function updateGalleryLanguage() {
  if (!gallery) return;
  const dictionary = copy[currentLanguage()];
  const caption = galleryCaption();
  galleryOpenButtons?.forEach((button) => {
    button.setAttribute("aria-label", dictionary.galleryOpen);
    button.setAttribute("title", dictionary.galleryOpen);
  });
  galleryPreviousButton?.setAttribute("aria-label", dictionary.galleryPrevious);
  galleryNextButton?.setAttribute("aria-label", dictionary.galleryNext);
  lightboxCloseButton?.setAttribute("aria-label", dictionary.galleryClose);
  lightboxPreviousButton?.setAttribute("aria-label", dictionary.galleryPrevious);
  lightboxNextButton?.setAttribute("aria-label", dictionary.galleryNext);
  if (galleryImage) galleryImage.alt = caption;
  if (galleryStatus) galleryStatus.textContent = `${dictionary.galleryPhoto} ${currentGalleryIndex + 1}: ${caption}`;
  galleryDots?.querySelectorAll(".mission-gallery__dot").forEach((dot, index) => dot.setAttribute("aria-label", `${dictionary.galleryPhoto} ${index + 1}`));
}
function showGallerySlide(index, animate = true) {
  if (!gallery || !galleryImage) return;
  currentGalleryIndex = (index + gallerySlides.length) % gallerySlides.length;
  const slide = gallerySlides[currentGalleryIndex];
  if (animate) gallery.classList.add("is-changing");
  window.setTimeout(() => {
    setImageSource(galleryImage, slide.src, galleryCaption());
    if (galleryCount) galleryCount.textContent = `${currentGalleryIndex + 1} / ${gallerySlides.length}`;
    updateGalleryDots();
    updateGalleryLanguage();
    requestAnimationFrame(() => gallery.classList.remove("is-changing"));
  }, animate ? 115 : 0);
}
function stopGalleryTimer() {
  if (!galleryTimer) return;
  window.clearInterval(galleryTimer);
  galleryTimer = null;
}
function startGalleryTimer() {
  if (!gallery || gallerySlides.length < 2 || document.hidden || lightbox?.classList.contains("is-open") || prefersReducedMotion.matches) return;
  stopGalleryTimer();
  galleryTimer = window.setInterval(() => showGallerySlide(currentGalleryIndex + 1), 6200);
}
function restartGalleryTimer() { stopGalleryTimer(); startGalleryTimer(); }
function initializeGallery() {
  if (!gallery) return;
  createGalleryDots();
  showGallerySlide(0, false);
  galleryPreviousButton?.addEventListener("click", () => { showGallerySlide(currentGalleryIndex - 1); restartGalleryTimer(); });
  galleryNextButton?.addEventListener("click", () => { showGallerySlide(currentGalleryIndex + 1); restartGalleryTimer(); });
  galleryOpenButtons?.forEach((button) => button.addEventListener("click", () => openLightbox(getGalleryItems(), currentGalleryIndex, button)));
  gallery.addEventListener("mouseenter", stopGalleryTimer);
  gallery.addEventListener("mouseleave", startGalleryTimer);
  gallery.addEventListener("focusin", stopGalleryTimer);
  gallery.addEventListener("focusout", () => window.setTimeout(startGalleryTimer, 0));
  gallery.addEventListener("touchstart", (event) => { galleryTouchStartX = event.changedTouches[0].screenX; }, { passive: true });
  gallery.addEventListener("touchend", (event) => {
    const distance = event.changedTouches[0].screenX - galleryTouchStartX;
    if (Math.abs(distance) < 45) return;
    showGallerySlide(distance < 0 ? currentGalleryIndex + 1 : currentGalleryIndex - 1);
    restartGalleryTimer();
  }, { passive: true });
  startGalleryTimer();
}

/* -------- Map location gallery: auto-rotates just like the main gallery -------- */
const placePins = document.querySelectorAll("[data-place]");
const placePanel = document.querySelector("[data-place-panel]");
const placeGallery = document.querySelector("[data-place-gallery]");
const placeImage = document.querySelector("[data-place-image]");
const placeDots = document.querySelector("[data-place-dots]");
const placePreviousButton = document.querySelector("[data-place-prev]");
const placeNextButton = document.querySelector("[data-place-next]");
const placeRegion = document.querySelector("[data-place-region]");
const placeTitle = document.querySelector("[data-place-title]");
const placeDescription = document.querySelector("[data-place-description]");
const placeList = document.querySelector("[data-place-list]");
let currentPlaceId = "mexico";
let currentPlaceImageIndex = 0;
let placeTimer = null;
let placeTouchStartX = 0;

function currentPlace() { return missionPlaces[currentPlaceId]; }
function getPlaceItems() {
  const place = currentPlace();
  return place.images.map((src, index) => ({ src, caption: `${place.title[currentLanguage()]} — ${copy[currentLanguage()].galleryPhoto} ${index + 1}` }));
}
function renderPlaceDots() {
  if (!placeDots) return;
  placeDots.innerHTML = "";
  currentPlace().images.forEach((_, index) => {
    const dot = document.createElement("button");
    dot.type = "button";
    dot.className = "place-gallery__dot";
    dot.setAttribute("aria-label", `${copy[currentLanguage()].galleryPhoto} ${index + 1}`);
    dot.addEventListener("click", () => { showPlaceImage(index); restartPlaceTimer(); });
    placeDots.appendChild(dot);
  });
}
function updatePlaceDots() {
  placeDots?.querySelectorAll(".place-gallery__dot").forEach((dot, index) => {
    dot.classList.toggle("is-active", index === currentPlaceImageIndex);
    dot.setAttribute("aria-current", String(index === currentPlaceImageIndex));
  });
}
function showPlaceImage(index, animate = true) {
  if (!placeImage || !placeGallery) return;
  const place = currentPlace();
  currentPlaceImageIndex = (index + place.images.length) % place.images.length;
  if (animate) placeGallery.classList.add("is-changing");
  window.setTimeout(() => {
    const item = getPlaceItems()[currentPlaceImageIndex];
    setImageSource(placeImage, item.src, item.caption);
    updatePlaceDots();
    requestAnimationFrame(() => placeGallery.classList.remove("is-changing"));
  }, animate ? 100 : 0);
}
function stopPlaceTimer() {
  if (!placeTimer) return;
  window.clearInterval(placeTimer);
  placeTimer = null;
}
function startPlaceTimer() {
  if (!placeGallery || currentPlace().images.length < 2 || document.hidden || lightbox?.classList.contains("is-open") || prefersReducedMotion.matches) return;
  stopPlaceTimer();
  placeTimer = window.setInterval(() => showPlaceImage(currentPlaceImageIndex + 1), 6500);
}
function restartPlaceTimer() { stopPlaceTimer(); startPlaceTimer(); }
function updatePlaceContent(renderDots = true) {
  if (!placePanel || !missionPlaces[currentPlaceId]) return;
  const place = currentPlace();
  const language = currentLanguage();
  placePins.forEach((pin) => {
    const isActive = pin.dataset.place === currentPlaceId;
    pin.classList.toggle("is-active", isActive);
    pin.setAttribute("aria-selected", String(isActive));
  });
  if (placeRegion) placeRegion.textContent = place.region[language];
  if (placeTitle) placeTitle.textContent = place.title[language];
  if (placeDescription) placeDescription.textContent = place.description[language];
  if (placeList) {
    placeList.innerHTML = "";
    place.points[language].forEach((point) => {
      const item = document.createElement("li");
      const text = document.createElement("p");
      text.dataset.readMore = "";
      text.dataset.readMoreMin = "280";
      text.textContent = point;
      item.appendChild(text);
      placeList.appendChild(item);
    });
  }
  placePreviousButton?.setAttribute("aria-label", copy[language].placePrevious);
  placeNextButton?.setAttribute("aria-label", copy[language].placeNext);
  if (renderDots || !placeDots?.children.length) renderPlaceDots();
  showPlaceImage(currentPlaceImageIndex, false);
  refreshReadMoreContent({ reset: true });
}
placePins.forEach((pin) => pin.addEventListener("click", () => {
  currentPlaceId = pin.dataset.place;
  currentPlaceImageIndex = 0;
  stopPlaceTimer();
  updatePlaceContent(true);
  placePanel?.focus({ preventScroll: true });
  startPlaceTimer();
}));
placePreviousButton?.addEventListener("click", () => { showPlaceImage(currentPlaceImageIndex - 1); restartPlaceTimer(); });
placeNextButton?.addEventListener("click", () => { showPlaceImage(currentPlaceImageIndex + 1); restartPlaceTimer(); });
placeGallery?.addEventListener("click", (event) => {
  if (event.target.closest("button")) return;
  openLightbox(getPlaceItems(), currentPlaceImageIndex, placeGallery);
});
placeGallery?.addEventListener("mouseenter", stopPlaceTimer);
placeGallery?.addEventListener("mouseleave", startPlaceTimer);
placeGallery?.addEventListener("focusin", stopPlaceTimer);
placeGallery?.addEventListener("focusout", () => window.setTimeout(startPlaceTimer, 0));
placeGallery?.addEventListener("touchstart", (event) => { placeTouchStartX = event.changedTouches[0].screenX; }, { passive: true });
placeGallery?.addEventListener("touchend", (event) => {
  const distance = event.changedTouches[0].screenX - placeTouchStartX;
  if (Math.abs(distance) < 45) return;
  showPlaceImage(distance < 0 ? currentPlaceImageIndex + 1 : currentPlaceImageIndex - 1);
  restartPlaceTimer();
}, { passive: true });

/* -------- Click-to-expand for every content photo outside a slideshow -------- */
function getZoomableGroupItems(image) {
  const group = image.dataset.zoomGroup;
  const images = group
    ? [...document.querySelectorAll(`img[data-zoomable][data-zoom-group="${group}"]`)]
    : [image];
  return images.map((item) => ({
    src: item.currentSrc || item.src,
    caption: item.dataset.zoomCaption || item.alt || ""
  }));
}
function refreshZoomableLabels() {
  document.querySelectorAll("img[data-zoomable]").forEach((image) => {
    image.setAttribute("aria-label", `${copy[currentLanguage()].galleryOpen}: ${image.alt || copy[currentLanguage()].galleryPhoto}`);
  });
}
function initializeZoomableImages() {
  document.querySelectorAll("img[data-zoomable]").forEach((image) => {
    image.classList.add("is-zoomable");
    image.setAttribute("role", "button");
    image.setAttribute("tabindex", "0");
    const open = () => {
      const items = getZoomableGroupItems(image);
      const index = [...document.querySelectorAll(`img[data-zoomable][data-zoom-group="${image.dataset.zoomGroup}"]`)].indexOf(image);
      openLightbox(items, Math.max(index, 0), image);
    };
    image.addEventListener("click", open);
    image.addEventListener("keydown", (event) => {
      if (event.key === "Enter" || event.key === " ") { event.preventDefault(); open(); }
    });
  });
  refreshZoomableLabels();
}


/* -------- Training photo gallery -------- */
const trainingGallery = document.querySelector("[data-training-gallery]");
const trainingImage = trainingGallery?.querySelector("[data-training-image]");
const trainingOpenButton = trainingGallery?.querySelector("[data-training-open]");
const trainingPreviousButton = trainingGallery?.querySelector("[data-training-prev]");
const trainingNextButton = trainingGallery?.querySelector("[data-training-next]");
const trainingDots = trainingGallery?.querySelector("[data-training-dots]");
const trainingCaption = trainingGallery?.querySelector("[data-training-caption]");
let currentTrainingIndex = 0;
let trainingTimer = null;
let trainingTouchStartX = 0;

function getTrainingItems() {
  return trainingSlides.map((slide) => ({ src: slide.src, caption: slide[currentLanguage()] }));
}

function createTrainingDots() {
  if (!trainingDots) return;
  trainingDots.innerHTML = "";

  trainingSlides.forEach((_, index) => {
    const dot = document.createElement("button");
    dot.type = "button";
    dot.className = "training-gallery__dot";
    dot.setAttribute("aria-label", `${copy[currentLanguage()].galleryPhoto} ${index + 1}`);
    dot.addEventListener("click", () => {
      showTrainingSlide(index);
      restartTrainingTimer();
    });
    trainingDots.appendChild(dot);
  });
}

function updateTrainingDots() {
  trainingDots?.querySelectorAll(".training-gallery__dot").forEach((dot, index) => {
    dot.classList.toggle("is-active", index === currentTrainingIndex);
    dot.setAttribute("aria-current", String(index === currentTrainingIndex));
  });
}

function updateTrainingGalleryLanguage() {
  if (!trainingGallery) return;
  const dictionary = copy[currentLanguage()];
  const caption = trainingSlides[currentTrainingIndex][currentLanguage()];

  trainingOpenButton?.setAttribute("aria-label", dictionary.galleryOpen);
  trainingOpenButton?.setAttribute("title", dictionary.galleryOpen);
  trainingPreviousButton?.setAttribute("aria-label", dictionary.galleryPrevious);
  trainingNextButton?.setAttribute("aria-label", dictionary.galleryNext);

  if (trainingImage) {
    trainingImage.alt = caption;
  }

  if (trainingCaption) {
    trainingCaption.textContent = caption;
  }

  trainingDots?.querySelectorAll(".training-gallery__dot").forEach((dot, index) => {
    dot.setAttribute("aria-label", `${dictionary.galleryPhoto} ${index + 1}`);
  });
}

function showTrainingSlide(index, animate = true) {
  if (!trainingGallery || !trainingImage) return;
  currentTrainingIndex = (index + trainingSlides.length) % trainingSlides.length;
  const slide = trainingSlides[currentTrainingIndex];

  if (animate) trainingGallery.classList.add("is-changing");

  window.setTimeout(() => {
    setImageSource(trainingImage, slide.src, slide[currentLanguage()]);
    updateTrainingDots();
    updateTrainingGalleryLanguage();
    requestAnimationFrame(() => trainingGallery.classList.remove("is-changing"));
  }, animate ? 115 : 0);
}

function stopTrainingTimer() {
  if (!trainingTimer) return;
  window.clearInterval(trainingTimer);
  trainingTimer = null;
}

function startTrainingTimer() {
  if (
    !trainingGallery ||
    trainingSlides.length < 2 ||
    document.hidden ||
    lightbox?.classList.contains("is-open") ||
    prefersReducedMotion.matches
  ) return;

  stopTrainingTimer();
  trainingTimer = window.setInterval(() => {
    showTrainingSlide(currentTrainingIndex + 1);
  }, 6500);
}

function restartTrainingTimer() {
  stopTrainingTimer();
  startTrainingTimer();
}

function initializeTrainingGallery() {
  if (!trainingGallery) return;

  createTrainingDots();
  showTrainingSlide(0, false);

  trainingPreviousButton?.addEventListener("click", () => {
    showTrainingSlide(currentTrainingIndex - 1);
    restartTrainingTimer();
  });

  trainingNextButton?.addEventListener("click", () => {
    showTrainingSlide(currentTrainingIndex + 1);
    restartTrainingTimer();
  });

  trainingOpenButton?.addEventListener("click", () => {
    openLightbox(getTrainingItems(), currentTrainingIndex, trainingOpenButton);
  });

  trainingGallery.addEventListener("mouseenter", stopTrainingTimer);
  trainingGallery.addEventListener("mouseleave", startTrainingTimer);
  trainingGallery.addEventListener("focusin", stopTrainingTimer);
  trainingGallery.addEventListener("focusout", () => window.setTimeout(startTrainingTimer, 0));
  trainingGallery.addEventListener("touchstart", (event) => {
    trainingTouchStartX = event.changedTouches[0].screenX;
  }, { passive: true });
  trainingGallery.addEventListener("touchend", (event) => {
    const distance = event.changedTouches[0].screenX - trainingTouchStartX;
    if (Math.abs(distance) < 45) return;
    showTrainingSlide(distance < 0 ? currentTrainingIndex + 1 : currentTrainingIndex - 1);
    restartTrainingTimer();
  }, { passive: true });

  startTrainingTimer();
}

/* -------- Digital Bible chapter opener -------- */
const bibleBookSelect = document.querySelector("[data-bible-book]");
const bibleChapterSelect = document.querySelector("[data-bible-chapter]");
const bibleOpenLink = document.querySelector("[data-bible-open]");
let selectedBibleBook = "John";
let selectedBibleChapter = 3;
function findBibleBook() { return bibleBooks.find((book) => book.en === selectedBibleBook) || bibleBooks[0]; }
function updateBibleChapters() {
  if (!bibleChapterSelect) return;
  const book = findBibleBook();
  if (selectedBibleChapter > book.chapters) selectedBibleChapter = 1;
  bibleChapterSelect.innerHTML = "";
  for (let chapter = 1; chapter <= book.chapters; chapter += 1) {
    const option = document.createElement("option");
    option.value = chapter;
    option.textContent = chapter;
    option.selected = chapter === selectedBibleChapter;
    bibleChapterSelect.appendChild(option);
  }
}
function updateBibleLink() {
  if (!bibleOpenLink) return;
  const book = findBibleBook();
  const language = currentLanguage();
  const title = language === "es" ? book.es : book.en;
  const version = language === "es" ? "RVR1960" : "NIV";
  const passage = encodeURIComponent(`${title} ${selectedBibleChapter}`);
  bibleOpenLink.href = `https://www.biblegateway.com/passage/?search=${passage}&version=${version}`;
}
function populateBibleBooks() {
  if (!bibleBookSelect || !bibleChapterSelect) return;
  const language = currentLanguage();
  const currentBook = findBibleBook();
  bibleBookSelect.innerHTML = "";
  bibleBooks.forEach((book) => {
    const option = document.createElement("option");
    option.value = book.en;
    option.textContent = book[language];
    option.selected = book.en === currentBook.en;
    bibleBookSelect.appendChild(option);
  });
  bibleBookSelect.setAttribute("aria-label", copy[language].bibleBookAria);
  bibleChapterSelect.setAttribute("aria-label", copy[language].bibleChapterAria);
  updateBibleChapters();
  updateBibleLink();
}
bibleBookSelect?.addEventListener("change", () => { selectedBibleBook = bibleBookSelect.value; selectedBibleChapter = 1; updateBibleChapters(); updateBibleLink(); });
bibleChapterSelect?.addEventListener("change", () => { selectedBibleChapter = Number(bibleChapterSelect.value); updateBibleLink(); });

/* -------- Keyboard and timer support -------- */
document.addEventListener("keydown", (event) => {
  if (event.key === "Escape") {
    if (lightbox?.classList.contains("is-open")) closeLightbox();
    else closeMenu();
  }
  if (!lightbox?.classList.contains("is-open")) return;
  if (event.key === "ArrowLeft") moveLightbox(-1);
  if (event.key === "ArrowRight") moveLightbox(1);
});
document.addEventListener("visibilitychange", () => {
  if (document.hidden) { stopGalleryTimer(); stopPlaceTimer(); stopTrainingTimer(); }
  else { startGalleryTimer(); startPlaceTimer(); startTrainingTimer(); }
});
prefersReducedMotion.addEventListener?.("change", () => { stopGalleryTimer(); stopPlaceTimer(); stopTrainingTimer(); startGalleryTimer(); startPlaceTimer(); startTrainingTimer(); });

document.getElementById("current-year").textContent = new Date().getFullYear();
attachImageFallbacks();
initializeGallery();
initializeTrainingGallery();
initializeZoomableImages();
initializeReadMoreContent();

const savedLanguage = localStorage.getItem("sgm-language");
const browserLanguage = navigator.language.toLowerCase().startsWith("es") ? "es" : "en";
setLanguage(savedLanguage || browserLanguage);
